{
 "level": "A1‚ÄìB1",
 "intro": "In this topic you will learn <strong>all main types of pronouns</strong> in the English language and their rules usage.",
 "rules": [
 {
 "label": "Personal",
 "color": "emerald",
 "text": "<strong>Personal pronouns</strong> - who acts:",
 "example": "I work. She reads. They play."
 },
 {
 "label": "Possessive",
 "color": "blue",
 "text": "<strong>Possessive forms</strong> - whose is it:",
 "example": "my book, mine, his, hers"
 },
 {
 "label": "Reflexive",
 "color": "amber",
 "text": "<strong>Reflexive pronouns</strong> - action on self:",
 "example": "I did it myself. She taught herself."
 }
 ]
}

{
 "title": "1. Types of pronouns",
 "intro": "There are several main types of pronouns in the English language:",
 "items": [
 {
 "label": "Personal",
 "title": "Personal",
 "subtitle": "I, you, he, she, it, we, they ‚Äî who does or receives action"
 },
 {
 "label": "Possessive",
 "title": "Possessive",
 "subtitle": "my/mine, your/yours, his, her/hers ‚Äî whose is it"
 },
 {
 "label": "Reflexive",
 "title": "Reverse",
 "subtitle": "myself, yourself, himself, herself ‚Äî action on self"
 },
 {
 "label": "Demonstrative",
 "title": "Indicative",
 "subtitle": "this, that, these, those ‚Äî indicate objects"
 },
 {
 "label": "Indefinite",
 "title": "Undefined",
 "subtitle": "someone, anybody, nothing ‚Äî indefinite persons/things"
 },
 {
 "label": "Relative",
 "title": "Relative",
 "subtitle": "who, which, that - connect the parts of the sentence"
 }
 ]
}

{
 "title": "2. Personal Pronouns)",
 "sections": [
 {
 "label": "Subject Pronouns ‚Äî Subject",
 "color": "emerald",
 "description": "Used as the <strong>subject</strong> of a sentence (who performs the action).",
 "examples": [
 {
 "en": "I work every day.",
 "ua": "I work every day."
 },
 {
 "en": "You are smart.",
 "ua": "You are smart."
 },
 {
 "en": "He reads books.",
 "ua": "He reads books."
 },
 {
 "en": "She likes music.",
 "ua": "She likes music."
 },
 {
 "en": "It is a cat.",
 "ua": "It is a cat."
 },
 {
 "en": "We are friends.",
 "ua": "We are friends."
 },
 {
 "en": "They play football.",
 "ua": "They play football."
 }
 ]
 },
 {
 "label": "Object Pronouns - Object",
 "color": "sky",
 "description": "Used as <strong>object</strong> (who/what gets the action).",
 "examples": [
 {
 "en": "Call me later.",
 "ua": "Call me later."
 },
 {
 "en": "I see you.",
 "ua": "I see you."
 },
 {
 "en": "She loves him.",
 "ua": "She loves him."
 },
 {
 "en": "I know her.",
 "ua": "I know her."
 },
 {
 "en": "Give it to me.",
 "ua": "Give it to me."
 },
 {
 "en": "They invited us.",
 "ua": "They invited us."
 },
 {
 "en": "I like them.",
 "ua": "I like them."
 }
 ]
 },
 {
 "label": "Table of personal pronouns",
 "color": "purple",
 "description": "Complete table of subject and object pronouns:",
 "examples": [
 {
 "en": "I ‚Üí me",
 "ua": "I ‚Üí me"
 },
 {
 "en": "you ‚Üí you",
 "ua": "you ‚Üí you"
 },
 {
 "en": "he ‚Üí him",
 "ua": "he ‚Üí him"
 },
 {
 "en": "she ‚Üí her",
 "ua": "she ‚Üí her"
 },
 {
 "en": "it ‚Üí it",
 "ua": "it ‚Üí it"
 },
 {
 "en": "we ‚Üí us",
 "ua": "we ‚Üí us"
 },
 {
 "en": "they ‚Üí them",
 "ua": "they ‚Üí them"
 }
 ],
 "note": "üìå Subject = subject (who acts), Object = object (whom/what)."
 }
 ]
}

{
 "title": "3. Possessive Forms (Possessive Forms) new.",
 "sections": [
 {
 "label": "Possessive Adjectives",
 "color": "blue",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "This is my book.",
 "ua": "This is my book."
 },
 {
 "en": "Your car is new.",
 "ua": "Your car is new."
 },
 {
 "en": "His name is John.",
 "ua": "His name is John."
 },
 {
 "en": "Her sister is a doctor.",
 "ua": "Her sister is a doctor."
 },
 {
 "en": "Its color is blue.",
 "ua": "Its color is blue."
 },
 {
 "en": "Our house is big.",
 "ua": "Our house is big."
 },
 {
 "en": "Their dog is cute.",
 "ua": "Their dog is cute."
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 },
 {
 "label": "Possessive Pronouns - Possessive pronouns",
 "color": "sky",
 "description": "<strong>Replace</strong> a noun (stand instead of it).",
 "examples": [
 {
 "en": "This book is mine.",
 "ua": "This book is mine."
 },
 {
 "en": "The car is yours.",
 "ua": "The car is yours."
 },
 {
 "en": "That pen is his.",
 "ua": "That pen is his."
 },
 {
 "en": "The bag is hers.",
 "ua": "The bag is hers."
 },
 {
 "en": "The house is ours.",
 "ua": "The house is ours."
 },
 {
 "en": "Those keys are theirs.",
 "ua": "Those keys are theirs."
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 },
 {
 "label": "Important",
 "color": "amber",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Its color is red. (possessive)",
 "ua": "Its color is red. (possessive)"
 },
 {
 "en": "It's a cat. (it is)",
 "ua": "It's a cat. (it is)"
 }
 ],
 "note": "üìå Its = possessive, It's = contraction of It is."
 }
 ]
}

{
 "title": "4. Reflexive Pronouns",
 "sections": [
 {
 "label": "Reflexive pronoun forms",
 "color": "purple",
 "description": "End in <strong>-self</strong> (singular) or <strong>-selves</strong> (plural).",
 "examples": [
 {
 "en": "I ‚Üí myself",
 "ua": "I ‚Üí myself"
 },
 {
 "en": "you ‚Üí yourself / yourselves",
 "ua": "you ‚Üí yourself / yourselves"
 },
 {
 "en": "he ‚Üí himself",
 "ua": "he ‚Üí himself"
 },
 {
 "en": "she ‚Üí herself",
 "ua": "she ‚Üí herself"
 },
 {
 "en": "it ‚Üí itself",
 "ua": "it ‚Üí itself"
 },
 {
 "en": "we ‚Üí ourselves",
 "ua": "we ‚Üí ourselves"
 },
 {
 "en": "they ‚Üí themselves",
 "ua": "they ‚Üí themselves"
 }
 ]
 },
 {
 "label": "When to use",
 "color": "emerald",
 "description": "When <strong>subject and object</strong> are the same person.",
 "examples": [
 {
 "en": "I taught myself English.",
 "ua": "I taught myself English."
 },
 {
 "en": "She cut herself.",
 "ua": "She cut herself."
 },
 {
 "en": "We enjoyed ourselves.",
 "ua": "We enjoyed ourselves."
 },
 {
 "en": "They did it themselves.",
 "ua": "They did it themselves."
 }
 ]
 },
 {
 "label": "Emphatic use",
 "color": "amber",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "I did it myself.",
 "ua": "I did it myself."
 },
 {
 "en": "The boss himself came.",
 "ua": "The boss himself came."
 },
 {
 "en": "She fixed the car herself.",
 "ua": "She fixed the car herself."
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 }
 ]
}

{
 "title": "5. Demonstrative Pronouns",
 "sections": [
 {
 "label": "This / That - Singular",
 "color": "blue",
 "description": "<strong>This</strong> is close, <strong>That</strong> is far.",
 "examples": [
 {
 "en": "This is my phone.",
 "ua": "This is my phone."
 },
 {
 "en": "That is your car.",
 "ua": "That is your car."
 },
 {
 "en": "I like this.",
 "ua": "I like this."
 },
 {
 "en": "What is that?",
 "ua": "What is that?"
 }
 ]
 },
 {
 "label": "These / Those - Plural",
 "color": "sky",
 "description": "<strong>These</strong> - near, <strong>Those</strong> are far away.",
 "examples": [
 {
 "en": "These are my books.",
 "ua": "These are my books."
 },
 {
 "en": "Those are your keys.",
 "ua": "Those are your keys."
 },
 {
 "en": "I want these.",
 "ua": "I want these."
 },
 {
 "en": "Those are expensive.",
 "ua": "Those are expensive."
 }
 ],
 "note": "üìå This/That = singular, These/Those = plural."
 }
 ]
}

{
 "title": "6. Other types of pronouns (overview)",
 "sections": [
 {
 "label": "Indefinite Pronouns",
 "color": "purple",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Someone is calling.",
 "ua": "Someone is calling."
 },
 {
 "en": "Anybody can do it.",
 "ua": "Anybody can do it."
 },
 {
 "en": "Nothing is impossible.",
 "ua": "Nothing is impossible."
 },
 {
 "en": "Everybody knows that.",
 "ua": "Everybody knows that."
 }
 ]
 },
 {
 "label": "Relative Pronouns ‚Äî Relative",
 "color": "emerald",
 "description": "Connect parts of a complex sentence. The man who called is my boss.",
 "examples": [
 {
 "en": "The man who called is my boss.",
 "ua": "The man who called is my boss."
 },
 {
 "en": "The book that I read was great.",
 "ua": "The book that I read was great."
 },
 {
 "en": "The car which is red is mine.",
 "ua": "The car which is red is mine."
 }
 ]
 },
 {
 "label": "Reciprocal Pronouns ‚Äî Mutual",
 "color": "amber",
 "description": "Indicate mutual action.",
 "examples": [
 {
 "en": "They love each other.",
 "ua": "They love each other."
 },
 {
 "en": "We help one another.",
 "ua": "We help one another."
 }
 ],
 "note": "üìå Each other = for two, One another = for many."
 }
 ]
}

{
 "title": "7. Comparison table of main pronouns",
 "intro": "Main forms of pronouns:",
 "rows": [
 {
 "en": "Subject",
 "ua": "Subject",
 "note": "I, you, he, she, it, we, they"
 },
 {
 "en": "Object",
 "ua": "Object",
 "note": "me, you, him, her, it, us, them"
 },
 {
 "en": "Possessive Adj.",
 "ua": "Possessive Adj.",
 "note": "my, your, his, her, its, our, their"
 },
 {
 "en": "Possessive Pron.",
 "ua": "Possessive Pron.",
 "note": "mine, yours, his, hers, ours, theirs"
 },
 {
 "en": "Reflexive",
 "ua": "Reflexive",
 "note": "myself, myself, himself, herself, itself, ourselves, yourselves, themselves"
 }
 ],
 "warning": "üìå Subject = subject, Object = attachment, Possessive = possessive, Reflexive = reflexive."
}

{
 "title": "8. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Confusion of subject and object pronouns.",
 "wrong": "Me and John went to the park.",
 "right": " ‚úÖ <span class=\"font-mono\">John and I went to the park.</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Confusion of its and it's.",
 "wrong": "Its a cat. / The dog wagged it's tail.",
 "right": " ‚úÖ <span class=\"font-mono\">It's a cat. / The dog wagged its tail.</span>"
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Omission of a reflexive pronoun.",
 "wrong": "I taught English.",
 "right": "‚Äã‚Äã‚Äã‚Äã <span class=\"font-mono\">I taught myself English.</span>"
 },
 {
 "label": "Error 4",
 "color": "purple",
 "title": "Using a possessive adjective without a noun.",
 "wrong": "This book is my.",
 "right": "‚Äã‚Äã‚Äã‚Äã‚Äã‚Äã Brief synopsis"
 }
 ]
}

